import { useEffect, useState } from "react";
import { io } from "socket.io-client";

function Room({ room, setPage }) {
  const [socket, setSocket] = useState(null);

  const [answer, setAnswer] = useState("");
  const [selected, setSelected] = useState([]);
  const [question, setQuestion] = useState(null);
  const [scores, setScores] = useState({});
  const [timeLeft, setTimeLeft] = useState(0);
  const [role, setRole] = useState("participant");

  const [started, setStarted] = useState(false);
  const [finished, setFinished] = useState(false);

  const [timerEnabled, setTimerEnabled] = useState(false);
  const [timeLimit, setTimeLimit] = useState(10);

  useEffect(() => {
    const newSocket = io("http://localhost:5000", {
      auth: { token: localStorage.getItem("token") },
    });

    setSocket(newSocket);

    newSocket.on("role", setRole);

    newSocket.emit("join_room", { roomCode: room });

    newSocket.on("receive_question", (q) => {
      setQuestion(q);
      setSelected([]);
      setAnswer("");
    });

    newSocket.on("timer_update", setTimeLeft);
    newSocket.on("update_scores", setScores);

    newSocket.on("quiz_finished", (s) => {
      setFinished(true);
      setScores(s);
    });

    return () => newSocket.disconnect();
  }, [room]);

  const sendTextAnswer = () => {
    socket?.emit("submit_answer", {
      answer,
      roomCode: room,
    });
  };

  return (
    <div className="container">
      {/* ВЫХОД */}
      <button
        className="secondary small-btn"
        onClick={() => setPage("dashboard")}
      >
        ⬅ Выйти
      </button>

      <h2>Комната: {room}</h2>

      {/* ВОПРОС */}
      {!finished && question && (
        <div style={{ marginBottom: "20px" }}>
          {question.imageUrl && (
            <img
              src={question.imageUrl}
              alt=""
              style={{ width: "100%", borderRadius: "10px" }}
            />
          )}

          <h3 style={{ textAlign: "center" }}>{question.text}</h3>

          {/* ВАРИАНТЫ */}
          <div style={{ display: "grid", gap: "10px" }}>
            {question.type !== "text" &&
              question.options.map((opt, i) => (
                <button
                  key={i}
                  onClick={() => {
                    if (question.type === "multiple") {
                      setSelected((prev) =>
                        prev.includes(opt)
                          ? prev.filter((o) => o !== opt)
                          : [...prev, opt]
                      );
                    } else {
                      socket?.emit("submit_answer", {
                        answer: opt,
                        roomCode: room,
                      });
                    }
                  }}
                  style={{
                    background: selected.includes(opt)
                      ? "#22c55e"
                      : "#3b82f6",
                  }}
                >
                  {opt}
                </button>
              ))}
          </div>

          {/* MULTIPLE */}
          {question.type === "multiple" && (
            <button
              style={{ marginTop: "10px" }}
              onClick={() =>
                socket?.emit("submit_answer", {
                  answer: selected,
                  roomCode: room,
                })
              }
            >
              Ответить
            </button>
          )}

          {/* TEXT */}
          {question.type === "text" && (
            <>
              <input
                placeholder="Ваш ответ..."
                value={answer}
                onChange={(e) => setAnswer(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && sendTextAnswer()}
              />
              <button onClick={sendTextAnswer}>Ответить</button>
            </>
          )}
        </div>
      )}

      {/* ТАЙМЕР */}
      {!finished && timeLeft > 0 && (
        <h2 style={{ textAlign: "center" }}>⏱ {timeLeft}</h2>
      )}

      {/* ЛИДЕРБОРД */}
      <h3>🏆 Таблица лидеров</h3>

      <div style={{ marginBottom: "20px" }}>
        {Object.entries(scores)
          .sort((a, b) => b[1].score - a[1].score)
          .map(([id, data], index) => (
            <div
              key={id}
              style={{
                display: "flex",
                justifyContent: "space-between",
                background: "#334155",
                padding: "8px",
                borderRadius: "6px",
                marginBottom: "5px",
              }}
            >
              <span>
                {index + 1}. {data.name}
              </span>
              <span>{data.score}</span>
            </div>
          ))}
      </div>

      {/* НАСТРОЙКИ */}
      {!started && role === "organizer" && (
        <div
          style={{
            background: "#334155",
            padding: "15px",
            borderRadius: "10px",
          }}
        >
          <h3>⚙ Настройки</h3>

          {/* красивый toggle */}
          <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
            <span>Таймер</span>
            <button
              className={timerEnabled ? "" : "secondary"}
              onClick={() => setTimerEnabled(!timerEnabled)}
            >
              {timerEnabled ? "Включен" : "Выключен"}
            </button>
          </div>

          {timerEnabled && (
            <input
              type="number"
              placeholder="секунды"
              value={timeLimit}
              onChange={(e) => setTimeLimit(Number(e.target.value))}
            />
          )}

          <button
            style={{ marginTop: "10px" }}
            onClick={() => {
              socket?.emit("start_quiz", {
                roomCode: room,
                timerEnabled,
                timeLimit,
              });
              setStarted(true);
            }}
          >
            🚀 Старт
          </button>
        </div>
      )}

      {/* NEXT */}
      {!finished && role === "organizer" && started && (
        <button
          onClick={() =>
            socket?.emit("next_question", { roomCode: room })
          }
        >
          ➡ Следующий вопрос
        </button>
      )}
    </div>
  );
}

export default Room;
